
import { defineComponent, reactive, ref } from "vue";
import { getItemMethodStandard, getJudgeBasis } from "@/server/http/api/user";

export default defineComponent({
  props: ["id", "productId"],
  emits: ["selectjudgment"],
  setup(props, { emit }) {
    const visible = ref<boolean>(false);
    const formState: any = reactive({
      judgment: [],
    });
    let judgmentList = ref([]);
    const showModal = () => {
      getJudgeBasis(props.productId).then((res: any) => {
        if (res.data.code === 200) {
          judgmentList.value = res.data.data;
        }
      });
      visible.value = true;
    };

    const handleOk = (e: MouseEvent) => {
      //console.log("judgment", formState.judgment);

      emit("selectjudgment", { id: props.id, judgment: formState.judgment });
      visible.value = false;
    };
    return {
      visible,
      showModal,
      handleOk,
      formState,
      judgmentList,
    };
  },
});
