
import { defineComponent, onMounted, ref } from "vue";
import SampleAdd from "./madal/SampleAdd.vue";
import SampleTable from "./madal/SampleTable.vue";
import { entrustDetail } from "@/server/http/api/entrust";

import { set } from "lodash";
import bus from "@/utils/bus";
import { message } from "ant-design-vue";
import { useRoute } from "vue-router";
export default defineComponent({
  components: { SampleAdd, SampleTable },
  name: "UpdateSample",

  setup() {
    const route: any = useRoute();
    // 添加样品
    let sampleList: any = ref([]);

    // ※ ※ ※ ※ ※ ※ ※ ※ ※ ※ ※ ※ ※ ※ ※ ※ ※ ※ ※
    entrustDetail(route.query.id).then((res: any) => {
      if (res.data.code === 200) {
        //console.log(res.data.data.samples);
        res.data.data.samples.map((item: any) => {
          let judgment: any = [];
          item.standardFileIdStr.map((val: any) => {
            judgment.push(val.standardName + "~" + val.standardId);
          });
          item.judgment = judgment;
        });

        sampleList.value = res.data.data.samples;

        bus.emit("UpdateSample", sampleList.value);
      }
    });
    // ※ ※ ※ ※ ※ ※ ※ ※ ※ ※ ※ ※ ※ ※ ※ ※ ※ ※ ※

    function addSample(sampleDetail: any) {
      Object.assign(sampleDetail, { judgment: [] });

      // 判断是否重复添加样品
      let flagSaple = sampleList.value.every((item: any) => {
        return item.id !== sampleDetail.id;
      });
      if (flagSaple) {
        sampleList.value.push(sampleDetail);
        //console.log("添加样品", sampleList);
      } else {
        message.info("样品已添加，不能重复添加同一个样品！");
      }
    }
    function delrow(id: number) {
      let delIndex = sampleList.value.findIndex((item: any) => {
        return item.id === id;
      });
      sampleList.value.splice(delIndex, 1);
    }

    // 选择判定依据
    function selectjudgment(options: any) {
      let addIndex = sampleList.value.findIndex((item: any) => {
        return item.id === options.id;
      });
      sampleList.value[addIndex].judgment = options.judgment;
    }

    function onSubmit() {
      bus.emit("obtain", route.query.id);
    }

    return {
      addSample,
      sampleList,
      delrow,
      selectjudgment,
      onSubmit,
    };
  },
});
