export function toTree(data: any) {
  // 删除 所有 children,以防止多次调用
  data.forEach(function (item: any) {
    delete item.children;
  });

  // 将数据存储为 以 id 为 KEY 的 map 索引数据列
  var map: any = {};
  data.forEach(function (item: any) {
    map[item.checkItemId] = item;
  });
  //        //console.log(map);
  var val: any = [];

  data.forEach(function (item: any) {
    // 以当前遍历项，的pid,去map对象中找到索引的id
    var parent = map[item.itemPid];
    // 好绕啊，如果找到索引，那么说明此项不在顶级当中,那么需要把此项添加到，他对应的父级中
    if (parent) {
      (parent.children || (parent.children = [])).push(Object.assign(item, { title: item.checkItemName, key: item.checkItemId }));
    } else {
      //如果没有在map中找到对应的索引ID,那么直接把 当前的item添加到 val结果集中，作为顶级
      val.push(Object.assign(item, { title: item.checkItemName, key: item.checkItemId }));
    }
  });

  return val;
}
